mapper.select:
SELECT ee.environment_event_id AS environmentEventId, ee.equipment_id AS equipmentId, e.equipment_code AS equipmentCode, e.equipment_name AS equipmentName, ee.env_temperature AS envTemperature, ee.env_humidity AS envHumidity, ee.env_particle_cnt AS envParticleCnt, ee.env_deviation_type AS envDeviationType, ee.env_correction_applied AS envCorrectionApplied, ee.env_detected_at AS envDetectedAt FROM environment_event ee INNER JOIN equipment e ON ee.equipment_id = e.equipment_id WHERE 1 = 1
AND ee.equipment_id = #{request.equipmentId}
AND ee.env_deviation_type = #{request.envDeviationType}
ORDER BY ee.environment_event_id DESC
